export const TRIGRAMS = ["乾", "兑", "离", "震", "巽", "坎", "艮", "坤"] as const;

/** 按上下卦组合查找 */
export function findGuaByTrigrams(upper: Trigram, lower: Trigram): Gua64Entry | undefined {
  return GUA64.find((g) => g.upper === upper && g.lower === lower);
}

/** 按名字查找 */
export function findGuaByName(name: string): Gua64Entry | undefined {
  return GUA64.find((g) => g.name === name);
}
